def min_max_product(spec: dict) -> int:
    """Product of the smallest and largest chain values."""
    nums = spec["nums"]
    if not nums:
        return 0
    lo = nums[0]
    hi = nums[0]
    for n in nums:
        if n < lo:
            lo = n
        if n > hi:
            hi = n
    return lo * hi

