def best_meeting_point(spec: dict) -> str:
    """Name and combined hop cost of the cheapest node both starts can reach."""
    adj = spec["adj"]
    da = {spec["a"]: 0}
    queue = [spec["a"]]
    while queue:
        n = queue.pop(0)
        for m in adj[n]:
            if m not in da:
                da[m] = da[n] + 1
                queue.append(m)
    db = {spec["b"]: 0}
    queue = [spec["b"]]
    while queue:
        n = queue.pop(0)
        for m in adj[n]:
            if m not in db:
                db[m] = db[n] + 1
                queue.append(m)
    best = ""
    cost = -1
    for n in sorted(adj):
        if n in da and n in db:
            c = da[n] + db[n]
            if cost == -1 or c < cost:
                best = n
                cost = c
    if cost == -1:
        return "none"
    return best + ":" + str(cost)

