def portal_fanout_total(spec: dict) -> int:
    """Total fan-out across portal nodes reachable from start."""
    adj = spec["adj"]; flags = spec["flags"]
    seen = []
    queue = [spec["start"]]
    while queue:
        n = queue.pop(0)
        if n in seen:
            continue
        seen.append(n)
        queue.extend(adj[n])
    total = 0
    for n in sorted(seen):
        if flags[n]:
            total += len(adj[n])
    return total

