def even_odd_depth_gap(spec: dict) -> int:
    """Even-depth value total minus odd-depth value total."""
    adj = spec["adj"]; vals = spec["vals"]
    depth = {spec["start"]: 0}
    queue = [spec["start"]]
    while queue:
        n = queue.pop(0)
        for m in adj[n]:
            if m not in depth:
                depth[m] = depth[n] + 1
                queue.append(m)
    gap = 0
    for n in depth:
        if depth[n] % 2 == 0:
            gap += vals[n]
        else:
            gap -= vals[n]
    return gap

