def overlap_report(spec: dict) -> str:
    """Report how many nodes both starts reach versus exactly one."""
    adj = spec["adj"]
    ra = []
    queue = [spec["a"]]
    while queue:
        n = queue.pop(0)
        if n in ra:
            continue
        ra.append(n)
        queue.extend(adj[n])
    rb = []
    queue = [spec["b"]]
    while queue:
        n = queue.pop(0)
        if n in rb:
            continue
        rb.append(n)
        queue.extend(adj[n])
    both = 0
    lone = 0
    for n in adj:
        ina = n in ra
        inb = n in rb
        if ina and inb:
            both += 1
        elif ina or inb:
            lone += 1
    return "both=" + str(both) + ";only=" + str(lone)

