def sale_purchases(spec: dict) -> int:
    """Items bought in order within budget after the sale discount."""
    wallet = spec["budget"]
    bought = 0
    for p in spec["prices"]:
        cost = p
        if p > spec["cap"]:
            cost = p - spec["off"]
        if wallet < cost:
            break
        wallet -= cost
        bought += 1
    return bought

